select distinct a.* from application a
inner join order_items oi on a.target_id = cast(oi.order_id as char)
where oi.merchant_id = #{merchantId}
and a.requester_type = #{requesterType}
and a.target_type = #{targetType}
and a.request_type = #{requestType}

    and a.target_id = #{orderId}


    and a.user_id = #{userId}

